// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

/** Pins the no-shared-writes contract for the primitive tuple and DISTINCT hot loops. */
public class LmdbNativeHotLoopCounterTest {

	@BeforeEach
	public void resetCounters() {
		PrimitiveTupleTable.PROBES.set(0L);
		PrimitiveTupleTable.INSERTIONS.set(0L);
		NativeDistinctTracker.PRIMITIVE_ROWS.set(0L);
		NativeDistinctTracker.OBJECT_ROWS.set(0L);
	}

	@Test
	public void primitiveTupleCountersStayThreadConfinedDuringHotLoop() {
		PrimitiveTupleTable table = new PrimitiveTupleTable(2, 4);
		long[] row = { 11L, 22L };
		int[] slots = { 0, 1 };

		assertThat(table.findOrInsert(row, slots, false)).isZero();
		assertThat(table.find(row, slots, false)).isZero();

		assertThat(PrimitiveTupleTable.PROBES).hasValue(0L);
		assertThat(PrimitiveTupleTable.INSERTIONS).hasValue(0L);
	}

	@Test
	public void distinctCountersStayThreadConfinedDuringHotLoop() {
		NativeDistinctTracker tracker = new NativeDistinctTracker(new int[] { 0, 1 });

		assertThat(tracker.add(new long[] { 11L, 22L })).isTrue();
		assertThat(tracker.add(new long[] { 11L, 22L })).isFalse();

		assertThat(NativeDistinctTracker.PRIMITIVE_ROWS).hasValue(0L);
		assertThat(NativeDistinctTracker.OBJECT_ROWS).hasValue(0L);
	}

	@Test
	public void primitiveTupleCountersPublishExactlyOnce() {
		PrimitiveTupleTable table = new PrimitiveTupleTable(2, 4, true);
		long[] row = { 11L, 22L };
		int[] slots = { 0, 1 };
		table.findOrInsert(row, slots, false);
		table.find(row, slots, false);

		assertThat(PrimitiveTupleTable.PROBES).hasValue(0L);
		assertThat(PrimitiveTupleTable.INSERTIONS).hasValue(0L);
		table.commitMetrics();
		table.commitMetrics();

		assertThat(PrimitiveTupleTable.PROBES).hasValue(2L);
		assertThat(PrimitiveTupleTable.INSERTIONS).hasValue(1L);
	}

	@Test
	public void distinctCountersPublishExactlyOnce() {
		NativeDistinctTracker primitive = new NativeDistinctTracker(new int[] { 0, 1 });
		NativeDistinctTracker object = new NativeDistinctTracker(new int[] { 0, 1, 2, 3, 4 });
		long[] row = { 11L, 22L, 33L, 44L, 55L };
		primitive.add(row);
		primitive.add(row);
		object.add(row);
		object.add(row);

		assertThat(NativeDistinctTracker.PRIMITIVE_ROWS).hasValue(0L);
		assertThat(NativeDistinctTracker.OBJECT_ROWS).hasValue(0L);
		primitive.commitMetrics();
		primitive.commitMetrics();
		object.commitMetrics();
		object.commitMetrics();

		assertThat(NativeDistinctTracker.PRIMITIVE_ROWS).hasValue(2L);
		assertThat(NativeDistinctTracker.OBJECT_ROWS).hasValue(2L);
	}
}
